import{_ as a,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"38. Uniform And Laundry Allowance","description":"","frontmatter":{"title":"38. Uniform And Laundry Allowance","eba":"Nurses and Midwives 2024-2028","topics":["allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/38-uniform-and-laundry-allowance.md","filePath":"ebas/nurses-midwives/allowances/38-uniform-and-laundry-allowance.md"}'),t={name:"ebas/nurses-midwives/allowances/38-uniform-and-laundry-allowance.md"};function l(i,e,s,d,p,m){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_38-uniform-and-laundry-allowance" tabindex="-1">38. Uniform And Laundry Allowance <a class="header-anchor" href="#_38-uniform-and-laundry-allowance" aria-label="Permalink to &quot;38. Uniform And Laundry Allowance&quot;">​</a></h1><p><strong>38.1</strong> Where an Employer requires an Employee to wear a particular type or style of uniform, the Employer will provide this at no cost to the Employee. Payment in lieu of providing the Uniform is not permitted.</p><p><strong>38.2</strong> Where a Uniform is not provided by the Employer, the Employee will be paid a uniform allowance at the daily or weekly rate set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, whichever is the lesser amount in total.</p><p><strong>38.3</strong> Where laundering by or at the expense of the Employer is not provided, the Employee will be paid a laundry allowance at the daily or weekly rate set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, whichever is the lesser amount in total.</p><p><strong>38.4</strong> The uniform allowances but not the laundry will be paid during all absences on leave, except absence on long service leave and absence on sick leave beyond 21 consecutive days. Where, prior to taking leave, an Employee was paid a uniform allowance other than at the weekly rate, the rate to be paid during absence on leave will be the average of the allowance paid during the four weeks immediately preceding the taking of leave.</p><p><strong>38.5</strong> Where an Employer provides an Employee with Uniforms, all articles so provided remain the property of the Employer.</p><p><strong>38.6</strong> For the purposes of this clause 38, Uniform means such apparel as may be required by the Employer.</p>',7)])])}const h=a(t,[["render",l]]);export{u as __pageData,h as default};
